SELECT 0 AS memberId, A.CN AS userId, A.DISPLAYNAME AS userName, A.DISPLAYNAME2 AS userName2, B.DISPLAYNAME AS userDeptname, B.DISPLAYNAME2 AS userDeptname2, A.tenant_id AS tenantId, $groupId$ AS groupId, $memberRoleId$ AS memberRoleId FROM tbl_usermaster A LEFT JOIN tbl_deptmaster B ON A.department = B.CN AND A.tenant_id = B.tenant_id WHERE A.tenant_id = #tenantId# AND A.CN IN (
#userId[]#
)

sqlMap.update:
UPDATE TBL_PMS_GROUP SET REAL_PROGRESS
= IFNULL(( SELECT SUM(a.REAL_PROGRESS * a.WEIGHT) / SUM(a.WEIGHT) FROM TBL_PMS_TASK a JOIN ( SELECT GROUP_ID FROM TBL_PMS_GROUP WHERE GROUP_ID IN ( SELECT GROUP_ID FROM TBL_PMS_GROUP WHERE GROUP_ID = #groupId# OR ancester_group like concat('%,',#groupId#,',%') OR ancester_group like concat(#groupId#,',%') ) AND TENANT_ID = #tenantId# AND DEL_STATUS = 0 ) b on a.GROUP_ID = b.GROUP_ID AND a.TENANT_ID = #tenantId# AND a.DEL_STATUS = 0
), 0) WHERE GROUP_ID = #groupId# AND TENANT_ID = #tenantId#
